BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?container ?containerName ?component ?componentName ?componentType WHERE {
  ?container rdf:type vocab:block ;
             vocab:NamedElement_name ?containerName .
  FILTER(
    CONTAINS(LCASE(STR(?containerName)), LCASE("aps")) &&
    CONTAINS(LCASE(STR(?containerName)), LCASE("conceptual"))
  )
  # Heuristic: prefer the one whose name contains “design” too
  OPTIONAL { ?container vocab:Element_ownedElement ?component . }
  OPTIONAL { ?container vocab:Namespace_ownedMember ?component . }
  ?component rdf:type ?componentType .
  OPTIONAL { ?component vocab:NamedElement_name ?componentName . }
}
ORDER BY DESC(
  (IF(CONTAINS(LCASE(STR(?containerName)), LCASE("design")), 1, 0)))
)
LIMIT 25

